namespace TranSmart.Service.Payroll
{
    public partial interface ITemplateService : IBaseService<Template>
    {

    }

    public partial class TemplateService : BaseService<Template>, ITemplateService
    {
        public TemplateService(IUnitOfWork uow) : base(uow)
        {

        }

        public override async Task Validation(Template item, Result<Template> executionResult)
        {
            if (await UOW.GetRepositoryAsync<Template>().HasRecordsAsync(x => x.Name == item.Name && x.Status == true && x.ID != item.ID))
            {
                executionResult.AddMessageItem(new MessageItem(nameof(Template.Name), "Name already exists"));
            }
        }
        public override async Task<Template> GetById(Guid id)
        {
            return await UOW.GetRepositoryAsync<Template>().SingleAsync(
                predicate: x => x.ID == id,
                orderBy: o => o.OrderByDescending(x => x.AddedAt));
        }

        public override async Task<IEnumerable<Template>> GetList(string orderBy)
        {
            return await UOW.GetRepositoryAsync<Template>().GetListAsync(orderBy, x => x.Status == true);
        }

        public override async Task<IPaginate<Template>> GetPaginate(BaseSearch search)
        {
            return await UOW.GetRepositoryAsync<Template>().GetPageListAsync(
                predicate: x => (string.IsNullOrEmpty(search.Name)
                     || x.Name.Contains(search.Name)),
                index: search.Page, size: search.Size, sortBy: search.SortBy ?? "Name", ascending: !search.IsDescend);
        }
    }
